dtsPropsFor.Button:
/** Visual style. Brand CTA = "accent" (green). */
variant?: "default" | "accent" | "outline" | "ghost" | "subtle" | "destructive" | "link";
/** Control height. "icon" is a 36px square for icon-only buttons. */
size?: "sm" | "md" | "lg" | "xl" | "icon";
// plus all native <button> attributes (onClick, disabled, type, …)

dtsPropsFor.Input:
type?: string;
placeholder?: string;
value?: string | number;
defaultValue?: string | number;
disabled?: boolean;
required?: boolean;
onChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
className?: string;
// plus all native <input> attributes

dtsPropsFor.Textarea:
rows?: number;
placeholder?: string;
value?: string;
defaultValue?: string;
disabled?: boolean;
onChange?: (e: React.ChangeEvent<HTMLTextAreaElement>) => void;
className?: string;
// plus all native <textarea> attributes

dtsPropsFor.ConfirmDialog:
open: boolean;
onOpenChange: (open: boolean) => void;
title: string;
description?: string;
confirmLabel?: string;
confirmDisabled?: boolean;
cancelLabel?: string;
/** Red confirm button for irreversible actions. */
destructive?: boolean;
onConfirm: () => void | Promise<void>;
children?: React.ReactNode;
/** Panel max-width Tailwind class. Default "max-w-md". */
maxWidthClass?: string;
/** Size to content (no min-height) — for lightweight confirms. */
compact?: boolean;

dtsPropsFor.FeedCard:
/** A published post. */
item: { id: number; author: { username: string; avatarUrl: string | null }; slug: string; title: string; excerpt: string | null; ogImageUrl: string | null; tags: string[]; publishedAt: string; likeCount: number };
/** Active locale, e.g. "ko". */
locale: string;
className?: string;
/** Drop the author from the meta row (single-author surfaces). */
hideAuthor?: boolean;
/** Lead post: larger title + an editorial label above it. */
featured?: boolean;
featuredLabel?: string;
flushTop?: boolean;
/** Show the save-to-reading-list toggle (needs a numeric item.id). */
showBookmark?: boolean;
eager?: boolean;

dtsPropsFor.DiscoveryCard:
/** A published post; cover variant when ogImageUrl is set, else a text variant. */
item: { id: number; author: { username: string; avatarUrl: string | null }; slug: string; title: string; excerpt: string | null; ogImageUrl: string | null; tags: string[]; publishedAt: string; likeCount: number; followReason?: { kind: "AUTHOR" | "SERIES" | "TOPIC"; tag: string | null } | null };
locale: string;
/** Larger lead tile. */
featured?: boolean;
eager?: boolean;

dtsPropsFor.KurlLinkCard:
/** Short-link code, e.g. "spring" (renders kurl.me/<code>). */
code: string;
/** Destination URL the card links to. */
url: string;

dtsPropsFor.TagChip:
href: string;
label: string;
/** Post count; hidden on the active chip. */
count?: number;
/** Brand-fill selected state (filter strips). */
active?: boolean;
ariaCurrent?: "page" | "true";
className?: string;
/** Render as a soft client-nav link (pass a same-origin relative href). */
soft?: boolean;
onClick?: () => void;

dtsPropsFor.Avatar:
/** Image URL; null/undefined falls back to the initial on an accent disc. */
src: string | null | undefined;
/** Author name — its first character is the fallback initial. */
name: string;
/** xs 20 · sm 28 · md 36 · lg 44 · xl 80 (px). */
size?: "xs" | "sm" | "md" | "lg" | "xl";
shrink?: boolean;

dtsPropsFor.ResultCard:
/** The created short link. */
result: { shortCode: string; shortUrl: string; claimToken: string | null };
/** The original long URL that was shortened. */
originalUrl: string;
/** Signed-in viewer → stats/profile CTAs; false → anonymous claim + 24h-expiry banner. */
authenticated: boolean;

dtsPropsFor.StatsCards:
total: number;
human: number;
bot: number;
unique?: number | null;
/** Clicks from the owner's public profile; renders an extra KPI only when > 0. */
profileClicks?: number | null;
timeToFirstClickMinutes?: number | null;
velocityRatio?: number | null;
/** Animate the count-up. Set false for static/SSR render. */
animate?: boolean;
onNavigate?: (section: string) => void;
